mapper.select:
select tu.Un_ID as unId, tu.Teacher_ID as teacherId, tu.Un_Week as unWeek, tu.Un_Weekday as unWeekday, tu.Un_Section as unSection, tu.Un_Remark as unRemark, te.Teacher_Name as teacherName from teacher_unavailable tu left join teacher te on tu.Teacher_ID = te.Teacher_ID
and tu.Teacher_ID = #{teacherId}
and tu.Un_Weekday = #{unWeekday}
order by tu.Un_ID limit #{offset}, #{pageSize}

select count(*)
from teacher_unavailable tu


        and tu.Teacher_ID = #{teacherId}


        and tu.Un_Weekday = #{unWeekday}
